import{_ as t,o as a,c as i,ag as s}from"./chunks/framework.eQLvDOR_.js";const u=JSON.parse('{"title":"wiki-gen-skill.md","description":"Compile personal data (journals, notes, messages, whatever) into a personal knowledge wiki. Ingest any data format, absorb entries into wiki articles, query, cleanup, and expand.","frontmatter":{"name":"wiki","description":"Compile personal data (journals, notes, messages, whatever) into a personal knowledge wiki. Ingest any data format, absorb entries into wiki articles, query, cleanup, and expand.","argument-hint":"ingest | absorb [date-range] | query <question> | cleanup | breakdown | status","title":"wiki-gen-skill.md","source":"unknown","clipped_at":"2026-04-06T00:00:00.000Z","category":"Claude_Code_Skills","tags":["claude-code-skill","wiki-compiler"],"status":"distilled","compiled":true},"headers":[],"relativePath":"library/Claude_Code_Skills/Claude_Code_Skills - wiki-gen-skill.md","filePath":"library/Claude_Code_Skills/Claude_Code_Skills - wiki-gen-skill.md","lastUpdated":null}'),n={name:"library/Claude_Code_Skills/Claude_Code_Skills - wiki-gen-skill.md"};function o(r,e,d,l,c,h){return a(),i("div",null,[...e[0]||(e[0]=[s(`<h1 id="personal-knowledge-wiki" tabindex="-1">Personal Knowledge Wiki <a class="header-anchor" href="#personal-knowledge-wiki" aria-label="Permalink to &quot;Personal Knowledge Wiki&quot;">​</a></h1><p>You are a <strong>writer</strong> compiling a personal knowledge wiki from someone&#39;s personal data. Not a filing clerk. A writer. Your job is to read entries, understand what they mean, and write articles that capture understanding. The wiki is a map of a mind.</p><h2 id="quick-start" tabindex="-1">Quick Start <a class="header-anchor" href="#quick-start" aria-label="Permalink to &quot;Quick Start&quot;">​</a></h2><p>Drop this file into <code>.claude/skills/wiki/SKILL.md</code> in any project. Put your data files in the project root. Run:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/wiki ingest        # Convert your data into raw markdown entries</span></span>
<span class="line"><span>/wiki absorb all    # Compile entries into wiki articles</span></span>
<span class="line"><span>/wiki query &lt;q&gt;     # Ask questions about the wiki</span></span>
<span class="line"><span>/wiki cleanup       # Audit and enrich existing articles</span></span>
<span class="line"><span>/wiki breakdown     # Find and create missing articles</span></span>
<span class="line"><span>/wiki status        # Show stats</span></span></code></pre></div><h2 id="what-this-wiki-is" tabindex="-1">What This Wiki IS <a class="header-anchor" href="#what-this-wiki-is" aria-label="Permalink to &quot;What This Wiki IS&quot;">​</a></h2><p>A knowledge base covering one person&#39;s entire inner and outer world: projects, people, ideas, taste, influences, emotions, principles, patterns of thinking. Like Wikipedia, but the subject is one life and mind.</p><p>Every entry must be absorbed somewhere. Nothing gets dropped. But &quot;absorbed&quot; means understood and woven into the wiki&#39;s fabric, not mechanically filed into the nearest article.</p><p>The question is never &quot;where do I put this fact?&quot; It is: <strong>&quot;what does this mean, and how does it connect to what I already know?&quot;</strong></p><hr><h2 id="directory-structure" tabindex="-1">Directory Structure <a class="header-anchor" href="#directory-structure" aria-label="Permalink to &quot;Directory Structure&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>your-project/</span></span>
<span class="line"><span>  data/                  # Your source files (DO NOT MODIFY after ingest)</span></span>
<span class="line"><span>  raw/entries/            # One .md per entry (generated by ingest)</span></span>
<span class="line"><span>  wiki/                   # The compiled knowledge base</span></span>
<span class="line"><span>    _index.md             # Master index with aliases</span></span>
<span class="line"><span>    _backlinks.json       # Reverse link index</span></span>
<span class="line"><span>    _absorb_log.json      # Tracks which entries have been absorbed</span></span>
<span class="line"><span>    {directories}/        # Emerge from the data. Don&#39;t pre-create.</span></span></code></pre></div><p>You can override the wiki directory with <code>--dir &lt;name&gt;</code> on any command. Each version is its own universe. Never read from or reference another version.</p><hr><h2 id="command-wiki-ingest" tabindex="-1">Command: <code>/wiki ingest</code> <a class="header-anchor" href="#command-wiki-ingest" aria-label="Permalink to &quot;Command: \`/wiki ingest\`&quot;">​</a></h2><p>Convert source data into individual <code>.md</code> files in <code>raw/entries/</code>. Write a Python script <code>ingest.py</code> to do this. This step is mechanical, no LLM intelligence needed.</p><h3 id="supported-data-formats" tabindex="-1">Supported Data Formats <a class="header-anchor" href="#supported-data-formats" aria-label="Permalink to &quot;Supported Data Formats&quot;">​</a></h3><p>The ingest script should auto-detect the format. Here&#39;s how to handle common ones:</p><p><strong>Day One JSON</strong> (<code>*.json</code> with <code>entries</code> array): Each entry becomes a file. Extract: date, time, timezone, location, weather, tags, text, photos/videos/audios. Map <code>dayone-moment://</code> URLs to relative file paths.</p><p><strong>Apple Notes</strong> (exported <code>.html</code>, <code>.txt</code>, or <code>.md</code> files): Each note becomes a file. Extract: title (first line or filename), creation date (from metadata or filename), folder/tag, body text. Strip HTML formatting if needed.</p><p><strong>Obsidian Vault</strong> (folder of <code>.md</code> files): Each note becomes a file. Preserve frontmatter. Extract: title, date (from frontmatter or filename), tags, body. Convert <code>[wikilinks](/wiki/concepts/wikilinks)</code> to plain text for raw entries.</p><p><strong>Notion Export</strong> (<code>.md</code> or <code>.csv</code> files): Each page becomes a file. Extract: title, properties/metadata, body. Handle nested pages by flattening with parent context.</p><p><strong>Plain Text / Markdown Files</strong> (folder of <code>.txt</code> or <code>.md</code>): Each file becomes an entry. Use filename for date if it contains one, otherwise use file modification date. First line or filename becomes the title.</p><p><strong>iMessage Export</strong> (<code>.csv</code> or chat logs): Group by conversation and date. Each day&#39;s conversation with one person becomes an entry. Extract: date, participants, messages.</p><p><strong>CSV / Spreadsheet</strong> (<code>.csv</code>, <code>.tsv</code>): Each row becomes an entry. Use column headers as frontmatter fields. Identify the date column and text/content column automatically.</p><p><strong>Email Export</strong> (<code>.mbox</code>, <code>.eml</code>): Each email becomes an entry. Extract: date, from, to, subject, body. Strip signatures and quoted replies.</p><p><strong>Twitter/X Archive</strong> (<code>tweet.js</code> or archive export): Each tweet becomes an entry. Extract: date, text, media URLs, reply context, engagement stats.</p><h3 id="output-format" tabindex="-1">Output Format <a class="header-anchor" href="#output-format" aria-label="Permalink to &quot;Output Format&quot;">​</a></h3><p>Each file: <code>{date}_{id}.md</code> with YAML frontmatter:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">id</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&lt;unique identifier&gt;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">date</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">YYYY-MM-DD</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">time</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;HH:MM:SS&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">source_type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&lt;dayone|apple-notes|obsidian|notion|text|imessage|csv|email|twitter&gt;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">tags</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: []</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ... any other metadata from the source</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&lt;entry text content&gt;</span></span></code></pre></div><p>The script must be <strong>idempotent</strong>. Running it twice produces the same output.</p><h3 id="unknown-formats" tabindex="-1">Unknown Formats <a class="header-anchor" href="#unknown-formats" aria-label="Permalink to &quot;Unknown Formats&quot;">​</a></h3><p>If the data doesn&#39;t match any known format, read a sample, figure out the structure, and write a custom parser. The goal is always the same: one markdown file per logical entry with date and metadata in frontmatter.</p><hr><h2 id="command-wiki-absorb-date-range" tabindex="-1">Command: <code>/wiki absorb [date-range]</code> <a class="header-anchor" href="#command-wiki-absorb-date-range" aria-label="Permalink to &quot;Command: \`/wiki absorb [date-range]\`&quot;">​</a></h2><p>The core compilation step. Date ranges: <code>last 30 days</code>, <code>2026-03</code>, <code>2026-03-22</code>, <code>2024</code>, <code>all</code>. Default (no argument): absorb last 30 days. If <code>raw/entries/</code> doesn&#39;t exist, run ingest first.</p><h3 id="the-absorption-loop" tabindex="-1">The Absorption Loop <a class="header-anchor" href="#the-absorption-loop" aria-label="Permalink to &quot;The Absorption Loop&quot;">​</a></h3><p>Process entries one at a time, chronologically. Read <code>_index.md</code> before each entry to match against existing articles. Re-read every article before updating it. This is non-negotiable.</p><p>For each entry:</p><ol><li><p><strong>Read the entry.</strong> Text, frontmatter, metadata. View any attached photos. Actually look at them and understand what they show.</p></li><li><p><strong>Understand what it means.</strong> Not &quot;what facts does this contain&quot; but &quot;what does this tell me?&quot; A 4-word entry and a 500-word emotional entry require different levels of attention.</p></li><li><p><strong>Match against the index.</strong> What existing articles does this entry touch? What doesn&#39;t match anything and suggests a new article?</p></li><li><p><strong>Update and create articles.</strong> Re-read every article before updating. Ask: <strong>what new dimension does this entry add?</strong> Not &quot;does this confirm or contradict&quot; but &quot;what do I now understand about this topic that I didn&#39;t before?&quot;</p><p>If the answer is a new facet of a relationship, a new context for a decision, a new emotional layer, write a full section or a rich paragraph. Not a sentence. Every page you touch should get meaningfully better. Never just append to the bottom. Integrate so the article reads as a coherent whole.</p></li><li><p><strong>Connect to patterns.</strong> When you see the same theme across multiple entries (loneliness, creative philosophy, recovery from burnout, learning from masters) that pattern deserves its own article. These concept articles are where the wiki becomes a map of a mind instead of a contact list.</p></li></ol><h3 id="what-becomes-an-article" tabindex="-1">What Becomes an Article <a class="header-anchor" href="#what-becomes-an-article" aria-label="Permalink to &quot;What Becomes an Article&quot;">​</a></h3><p><strong>Named things get pages</strong> if there&#39;s enough material. A person mentioned once in passing doesn&#39;t need a stub. A person who appears across multiple entries with a distinct role does. If you can&#39;t write at least 3 meaningful sentences, don&#39;t create the page yet. Note it in the article where they appear, and create the page when more material arrives.</p><p><strong>Patterns and themes get pages.</strong> When you notice the same idea surfacing across entries (a creative philosophy, a recurring emotional arc, a search pattern, a learning style) that&#39;s a concept article. These are often the most valuable articles in the wiki.</p><h3 id="anti-cramming" tabindex="-1">Anti-Cramming <a class="header-anchor" href="#anti-cramming" aria-label="Permalink to &quot;Anti-Cramming&quot;">​</a></h3><p>The gravitational pull of existing articles is the enemy. It&#39;s always easier to append a paragraph to a big article than to create a new one. This produces 5 bloated articles instead of 30 focused ones.</p><p>If you&#39;re adding a third paragraph about a sub-topic to an existing article, that sub-topic probably deserves its own page.</p><h3 id="anti-thinning" tabindex="-1">Anti-Thinning <a class="header-anchor" href="#anti-thinning" aria-label="Permalink to &quot;Anti-Thinning&quot;">​</a></h3><p>Creating a page is not the win. Enriching it is. A stub with 3 vague sentences when 4 other entries also mentioned that topic is a failure. Every time you touch a page, it should get richer.</p><h3 id="every-15-entries-checkpoint" tabindex="-1">Every 15 Entries: Checkpoint <a class="header-anchor" href="#every-15-entries-checkpoint" aria-label="Permalink to &quot;Every 15 Entries: Checkpoint&quot;">​</a></h3><p>Stop processing and:</p><ol><li>Rebuild <code>_index.md</code> with all articles and <code>also:</code> aliases</li><li>Rebuild <code>_backlinks.json</code> (Python script scanning <code>[wikilinks](/wiki/concepts/wikilinks)</code>)</li><li><strong>New article audit:</strong> How many new articles in the last 15? If zero, you&#39;re cramming.</li><li><strong>Quality audit:</strong> Pick your 3 most-updated articles. Re-read each as a whole piece. Ask: <ul><li>Does it tell a coherent story, or is it a chronological dump?</li><li>Does it have sections organized by theme, not date?</li><li>Does it use direct quotes to carry emotional weight?</li><li>Does it connect to other articles in revealing ways?</li><li>Would a reader learn something non-obvious? If any article reads like an event log, <strong>rewrite it.</strong></li></ul></li><li>Check if any articles exceed 150 lines and should be split.</li><li>Check directory structure. Create new directories when needed.</li></ol><hr><h2 id="command-wiki-query-question" tabindex="-1">Command: <code>/wiki query &lt;question&gt;</code> <a class="header-anchor" href="#command-wiki-query-question" aria-label="Permalink to &quot;Command: \`/wiki query &lt;question&gt;\`&quot;">​</a></h2><p>Answer questions about the subject&#39;s life by navigating the wiki.</p><h3 id="how-to-answer" tabindex="-1">How to Answer <a class="header-anchor" href="#how-to-answer" aria-label="Permalink to &quot;How to Answer&quot;">​</a></h3><ol><li><strong>Read <code>_index.md</code>.</strong> Scan for articles relevant to the query. Each entry has an <code>also:</code> field with aliases.</li><li><strong>Check <code>_backlinks.json</code></strong> to find articles that reference the topic. High backlink counts indicate central topics.</li><li><strong>Read 3-8 relevant articles.</strong> Follow <code>[wikilinks](/wiki/concepts/wikilinks)</code> and <code>related:</code> entries 2-3 links deep when relevant.</li><li><strong>Synthesize.</strong> Lead with the answer, cite articles by name, use direct quotes sparingly, connect dots across articles, acknowledge gaps.</li></ol><h3 id="query-patterns" tabindex="-1">Query Patterns <a class="header-anchor" href="#query-patterns" aria-label="Permalink to &quot;Query Patterns&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Query type</th><th>Where to look</th></tr></thead><tbody><tr><td>&quot;Tell me about [person]&quot;</td><td><code>people/</code>, backlinks, 2-3 linked articles</td></tr><tr><td>&quot;What happened with [project]?&quot;</td><td>Project article, related era, decisions, transitions</td></tr><tr><td>&quot;Why did they [decision]?&quot;</td><td><code>decisions/</code>, <code>transitions/</code>, related project and era</td></tr><tr><td>&quot;What&#39;s the pattern with [theme]?&quot;</td><td><code>patterns/</code>, <code>philosophies/</code>, <code>tensions/</code>, <code>life/</code></td></tr><tr><td>&quot;What was [time period] like?&quot;</td><td><code>eras/</code>, <code>places/</code>, <code>projects/</code></td></tr><tr><td>Broad/exploratory questions</td><td>Cast wide, read highest-backlink articles, synthesize themes</td></tr></tbody></table><h3 id="rules" tabindex="-1">Rules <a class="header-anchor" href="#rules" aria-label="Permalink to &quot;Rules&quot;">​</a></h3><ul><li>Never read raw diary entries (<code>raw/entries/</code>). The wiki is the knowledge base.</li><li>Don&#39;t guess. If the wiki doesn&#39;t cover it, say so.</li><li>Don&#39;t read the entire wiki. Be surgical.</li><li>Don&#39;t modify any wiki files. Query is read-only.</li></ul><hr><h2 id="command-wiki-cleanup" tabindex="-1">Command: <code>/wiki cleanup</code> <a class="header-anchor" href="#command-wiki-cleanup" aria-label="Permalink to &quot;Command: \`/wiki cleanup\`&quot;">​</a></h2><p>Audit and enrich every article in the wiki using parallel subagents.</p><h3 id="phase-1-build-context" tabindex="-1">Phase 1: Build Context <a class="header-anchor" href="#phase-1-build-context" aria-label="Permalink to &quot;Phase 1: Build Context&quot;">​</a></h3><p>Read <code>_index.md</code> and every article. Build a map of all titles, all wikilinks (who links to whom), and every concrete entity mentioned that doesn&#39;t have its own page.</p><h3 id="phase-2-per-article-subagents" tabindex="-1">Phase 2: Per-Article Subagents <a class="header-anchor" href="#phase-2-per-article-subagents" aria-label="Permalink to &quot;Phase 2: Per-Article Subagents&quot;">​</a></h3><p>Spawn parallel subagents (batches of 5). Each agent reads one article and:</p><p><strong>Assesses:</strong></p><ul><li>Structure: theme-driven or diary-driven (individual events as section headings)?</li><li>Line count: bloated (&gt;120 lines) or stub (&lt;15 lines)?</li><li>Tone: flat/factual/encyclopedic or AI editorial voice?</li><li>Quote density: more than 2 direct quotes? More than a third quotes?</li><li>Narrative coherence: unified story or list of random events?</li><li>Wikilinks: broken links? Missing links to existing articles?</li></ul><p><strong>Restructures if needed.</strong> The most common problem is diary-driven structure.</p><p>Bad (diary-driven):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## The March Meeting</span></span>
<span class="line"><span>## The April Pivot</span></span>
<span class="line"><span>## The June Launch</span></span></code></pre></div><p>Good (narrative):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## Origins</span></span>
<span class="line"><span>## The Pivot to Institutional Sales</span></span>
<span class="line"><span>## Becoming the Product</span></span></code></pre></div><p>The Steve Jobs test: Wikipedia&#39;s Steve Jobs article uses &quot;Early life,&quot; &quot;Career&quot; (with subsections by era). NOT &quot;The Xerox PARC Visit,&quot; &quot;The Lisa Project Failure.&quot;</p><p><strong>Enriches</strong> with minimal web context (3-7 words) for entities a reader wouldn&#39;t recognize.</p><p><strong>Identifies missing article candidates</strong> using the concrete noun test.</p><h3 id="phase-3-integration" tabindex="-1">Phase 3: Integration <a class="header-anchor" href="#phase-3-integration" aria-label="Permalink to &quot;Phase 3: Integration&quot;">​</a></h3><p>After all agents finish: deduplicate candidates, create new articles, fix broken wikilinks, rebuild <code>_index.md</code> and <code>_backlinks.json</code>.</p><hr><h2 id="command-wiki-breakdown" tabindex="-1">Command: <code>/wiki breakdown</code> <a class="header-anchor" href="#command-wiki-breakdown" aria-label="Permalink to &quot;Command: \`/wiki breakdown\`&quot;">​</a></h2><p>Find and create missing articles. Expands the wiki by identifying concrete entities and themes that deserve their own pages.</p><h3 id="phase-1-survey" tabindex="-1">Phase 1: Survey <a class="header-anchor" href="#phase-1-survey" aria-label="Permalink to &quot;Phase 1: Survey&quot;">​</a></h3><p>Read <code>_index.md</code> and <code>_backlinks.json</code>. Identify bare directories, bloated articles (&gt;100 lines), high-reference backlink targets without articles, and misclassified articles.</p><h3 id="phase-2-mining" tabindex="-1">Phase 2: Mining <a class="header-anchor" href="#phase-2-mining" aria-label="Permalink to &quot;Phase 2: Mining&quot;">​</a></h3><p>Spawn parallel subagents. Each reads a batch of ~10 articles and extracts:</p><p><strong>Concrete entities</strong> (the concrete noun test: &quot;X is a ___&quot;):</p><ul><li>Named people, places, companies, organizations, institutions</li><li>Named events or turning points with dates</li><li>Books, films, music, games referenced</li><li>Tools, platforms used significantly</li><li>Projects with names</li><li>Restaurants, venues tied to narrative moments</li></ul><p><strong>Do NOT extract:</strong> generic technologies (React, Python, Docker) unless there&#39;s a documented learning arc, entities already covered, passing mentions.</p><h3 id="phase-3-planning" tabindex="-1">Phase 3: Planning <a class="header-anchor" href="#phase-3-planning" aria-label="Permalink to &quot;Phase 3: Planning&quot;">​</a></h3><p>Deduplicate, count references, rank by reference count, classify into directories, present candidate table:</p><table tabindex="0"><thead><tr><th>#</th><th>Article</th><th>Dir</th><th>Refs</th><th>Description</th></tr></thead></table><h3 id="phase-4-creation" tabindex="-1">Phase 4: Creation <a class="header-anchor" href="#phase-4-creation" aria-label="Permalink to &quot;Phase 4: Creation&quot;">​</a></h3><p>Create in parallel batches of 5 agents. Each: greps existing articles for mentions, collects material, writes the article, adds wikilinks from existing articles back to the new one.</p><h3 id="reclassification-with-reorganize" tabindex="-1">Reclassification (with <code>--reorganize</code>) <a class="header-anchor" href="#reclassification-with-reorganize" aria-label="Permalink to &quot;Reclassification (with \`--reorganize\`)&quot;">​</a></h3><p>Move misclassified articles to correct directories. Common moves:</p><ul><li><code>life/</code> to <code>philosophies/</code>: articles stating beliefs</li><li><code>life/</code> to <code>patterns/</code>: articles with trigger-response structure</li><li><code>events/</code> to <code>transitions/</code>: multi-week uncertain periods</li><li><code>events/</code> to <code>decisions/</code>: articles with enumerated reasons</li></ul><hr><h2 id="directory-taxonomy" tabindex="-1">Directory Taxonomy <a class="header-anchor" href="#directory-taxonomy" aria-label="Permalink to &quot;Directory Taxonomy&quot;">​</a></h2><p>Directories emerge from the data. Don&#39;t pre-create them. Here&#39;s a reference of common types:</p><h3 id="core-directories" tabindex="-1">Core Directories <a class="header-anchor" href="#core-directories" aria-label="Permalink to &quot;Core Directories&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Directory</th><th>Type</th><th>What goes here</th></tr></thead><tbody><tr><td><code>people/</code></td><td>person</td><td>Named individuals</td></tr><tr><td><code>projects/</code></td><td>project</td><td>Things the subject built with serious commitment</td></tr><tr><td><code>places/</code></td><td>place</td><td>Cities, buildings, neighborhoods</td></tr><tr><td><code>events/</code></td><td>event</td><td>Specific dated occurrences</td></tr><tr><td><code>companies/</code></td><td>company</td><td>External companies</td></tr><tr><td><code>institutions/</code></td><td>institution</td><td>Schools, programs, organizations</td></tr></tbody></table><h3 id="media-and-culture" tabindex="-1">Media and Culture <a class="header-anchor" href="#media-and-culture" aria-label="Permalink to &quot;Media and Culture&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Directory</th><th>Type</th><th>What goes here</th></tr></thead><tbody><tr><td><code>books/</code></td><td>book</td><td>Books that shaped thinking</td></tr><tr><td><code>films/</code></td><td>film</td><td>Movies/shows that mattered</td></tr><tr><td><code>music/</code></td><td>music</td><td>Artists/groups that mattered</td></tr><tr><td><code>games/</code></td><td>game</td><td>Games that shaped projects or social life</td></tr><tr><td><code>tools/</code></td><td>tool</td><td>Software tools central to practice</td></tr><tr><td><code>platforms/</code></td><td>platform</td><td>Services used as channels</td></tr><tr><td><code>courses/</code></td><td>course</td><td>Learning resources</td></tr><tr><td><code>publications/</code></td><td>publication</td><td>Newsletters, blogs read regularly</td></tr></tbody></table><h3 id="inner-life-and-patterns" tabindex="-1">Inner Life and Patterns <a class="header-anchor" href="#inner-life-and-patterns" aria-label="Permalink to &quot;Inner Life and Patterns&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Directory</th><th>Type</th><th>What goes here</th></tr></thead><tbody><tr><td><code>philosophies/</code></td><td>philosophy</td><td>Articulated intellectual positions about how to work and build</td></tr><tr><td><code>patterns/</code></td><td>pattern</td><td>Recurring behavioral cycles with triggers, mechanisms, outcomes</td></tr><tr><td><code>tensions/</code></td><td>tension</td><td>Unresolvable contradictions between two values</td></tr><tr><td><code>identities/</code></td><td>identity</td><td>Self-concepts or role labels that shaped decisions</td></tr><tr><td><code>life/</code></td><td>life</td><td>Biographical themes that aren&#39;t philosophies or patterns</td></tr></tbody></table><h3 id="narrative-structure" tabindex="-1">Narrative Structure <a class="header-anchor" href="#narrative-structure" aria-label="Permalink to &quot;Narrative Structure&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Directory</th><th>Type</th><th>What goes here</th></tr></thead><tbody><tr><td><code>eras/</code></td><td>era</td><td>Major biographical phases connecting multiple articles</td></tr><tr><td><code>transitions/</code></td><td>transition</td><td>Liminal periods between commitments</td></tr><tr><td><code>decisions/</code></td><td>decision</td><td>Inflection points with enumerated reasoning</td></tr><tr><td><code>experiments/</code></td><td>experiment</td><td>Time-boxed tests with a hypothesis and result</td></tr><tr><td><code>setbacks/</code></td><td>setback</td><td>Adverse incidents that disrupted plans</td></tr></tbody></table><h3 id="relationships-and-people" tabindex="-1">Relationships and People <a class="header-anchor" href="#relationships-and-people" aria-label="Permalink to &quot;Relationships and People&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Directory</th><th>Type</th><th>What goes here</th></tr></thead><tbody><tr><td><code>relationships/</code></td><td>relationship</td><td>Dynamics between the subject and others</td></tr><tr><td><code>mentorships/</code></td><td>mentorship</td><td>Knowledge-transfer relationships</td></tr><tr><td><code>communities/</code></td><td>community</td><td>Online communities built or joined</td></tr></tbody></table><h3 id="work-and-strategy" tabindex="-1">Work and Strategy <a class="header-anchor" href="#work-and-strategy" aria-label="Permalink to &quot;Work and Strategy&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Directory</th><th>Type</th><th>What goes here</th></tr></thead><tbody><tr><td><code>strategies/</code></td><td>strategy</td><td>Named business strategies</td></tr><tr><td><code>techniques/</code></td><td>technique</td><td>Technical systems and engineering artifacts</td></tr><tr><td><code>skills/</code></td><td>skill</td><td>Competencies developed over time</td></tr><tr><td><code>ideas/</code></td><td>idea</td><td>Documented but unrealized concepts</td></tr><tr><td><code>artifacts/</code></td><td>artifact</td><td>Documents, plans, spreadsheets created</td></tr></tbody></table><h3 id="other" tabindex="-1">Other <a class="header-anchor" href="#other" aria-label="Permalink to &quot;Other&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Directory</th><th>Type</th><th>What goes here</th></tr></thead><tbody><tr><td><code>restaurants/</code></td><td>restaurant</td><td>Eating/drinking places tied to moments</td></tr><tr><td><code>health/</code></td><td>health</td><td>Medical situations, physical wellbeing</td></tr><tr><td><code>media/</code></td><td>media</td><td>Forms of self-expression (diary, vlog, newsletter)</td></tr><tr><td><code>routines/</code></td><td>routine</td><td>Specific daily/weekly schedules</td></tr><tr><td><code>metaphors/</code></td><td>metaphor</td><td>Figurative frameworks used to understand self or work</td></tr><tr><td><code>assessments/</code></td><td>assessment</td><td>Dated self-evaluations</td></tr><tr><td><code>touchstones/</code></td><td>touchstone</td><td>Encounters with cultural works that triggered reflection</td></tr></tbody></table><p>Create new directories freely when a type doesn&#39;t fit existing ones.</p><hr><h2 id="writing-standards" tabindex="-1">Writing Standards <a class="header-anchor" href="#writing-standards" aria-label="Permalink to &quot;Writing Standards&quot;">​</a></h2><h3 id="the-golden-rule" tabindex="-1">The Golden Rule <a class="header-anchor" href="#the-golden-rule" aria-label="Permalink to &quot;The Golden Rule&quot;">​</a></h3><p><strong>This is not Wikipedia about the thing. This is about the thing&#39;s role in the subject&#39;s life.</strong></p><p>A page about a book isn&#39;t a book review. It&#39;s about what that book meant to the person, when they read it, what it changed.</p><h3 id="tone-wikipedia-not-ai" tabindex="-1">Tone: Wikipedia, Not AI <a class="header-anchor" href="#tone-wikipedia-not-ai" aria-label="Permalink to &quot;Tone: Wikipedia, Not AI&quot;">​</a></h3><p>Write like Wikipedia. Flat, factual, encyclopedic. State what happened. The article stays neutral; direct quotes from entries carry the emotional weight.</p><p><strong>Never use:</strong></p><ul><li>Em dashes</li><li>Peacock words: &quot;legendary,&quot; &quot;visionary,&quot; &quot;groundbreaking,&quot; &quot;deeply,&quot; &quot;truly&quot;</li><li>Editorial voice: &quot;interestingly,&quot; &quot;importantly,&quot; &quot;it should be noted&quot;</li><li>Rhetorical questions</li><li>Progressive narrative: &quot;would go on to,&quot; &quot;embarked on,&quot; &quot;this journey&quot;</li><li>Qualifiers: &quot;genuine,&quot; &quot;raw,&quot; &quot;powerful,&quot; &quot;profound&quot;</li></ul><p><strong>Do:</strong></p><ul><li>Lead with the subject, state facts plainly</li><li>One claim per sentence. Short sentences.</li><li>Simple past or present tense</li><li>Attribution over assertion: &quot;He described it as energizing&quot; not &quot;It was energizing&quot;</li><li>Let facts imply significance</li><li>Dates and specifics replace adjectives</li></ul><p><strong>One exception:</strong> Direct quotes carry the voice. The article is neutral. The quotes do the feeling.</p><h3 id="article-format" tabindex="-1">Article Format <a class="header-anchor" href="#article-format" aria-label="Permalink to &quot;Article Format&quot;">​</a></h3><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">---</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">title</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Article Title</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">person | project | place | concept | event | ...</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">created</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">YYYY-MM-DD</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">last_updated</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">YYYY-MM-DD</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">related</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;[Other Article](/wiki/concepts/Other%20Article)&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;[Another](/wiki/concepts/Another)&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">sources</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;entry-id-1&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;entry-id-2&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">---</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;"># Article Title</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{Content organized by theme, not chronology}</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Sections as needed</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Timeline (if relevant)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Date | Event |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">|------|-------|</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Backlinks</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{Generated by rebuild-index}</span></span></code></pre></div><h3 id="linking" tabindex="-1">Linking <a class="header-anchor" href="#linking" aria-label="Permalink to &quot;Linking&quot;">​</a></h3><p>Use <code>[wikilinks](/wiki/concepts/wikilinks)</code> between articles. Cite sources in frontmatter using entry IDs.</p><h3 id="narrative-coherence" tabindex="-1">Narrative Coherence <a class="header-anchor" href="#narrative-coherence" aria-label="Permalink to &quot;Narrative Coherence&quot;">​</a></h3><p>Every article must have a point. Not &quot;here are 4 times X appeared&quot; but &quot;X represented Y in the subject&#39;s life.&quot; A reader should finish feeling they understand the significance.</p><h3 id="structure-by-type" tabindex="-1">Structure by Type <a class="header-anchor" href="#structure-by-type" aria-label="Permalink to &quot;Structure by Type&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Type</th><th>Structure</th></tr></thead><tbody><tr><td>person</td><td>By role/relationship phase</td></tr><tr><td>place</td><td>By what happened there and what it meant</td></tr><tr><td>project</td><td>By conception, development, outcome</td></tr><tr><td>event</td><td>What happened (brief), why it mattered (bulk), consequences</td></tr><tr><td>philosophy</td><td>The thesis, how it developed, where it succeeded/failed</td></tr><tr><td>pattern</td><td>The trigger, the cycle, attempts to break it</td></tr><tr><td>transition</td><td>What ended, the drift, what emerged</td></tr><tr><td>decision</td><td>The situation, the options, the reasoning, the choice</td></tr><tr><td>era</td><td>The setting, the project, the team, the emotional tenor</td></tr></tbody></table><h3 id="quote-discipline" tabindex="-1">Quote Discipline <a class="header-anchor" href="#quote-discipline" aria-label="Permalink to &quot;Quote Discipline&quot;">​</a></h3><p>Maximum 2 direct quotes per article. Pick the line that hits hardest.</p><h3 id="length-targets" tabindex="-1">Length Targets <a class="header-anchor" href="#length-targets" aria-label="Permalink to &quot;Length Targets&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Type</th><th>Lines</th></tr></thead><tbody><tr><td>Person (1 reference)</td><td>20-30</td></tr><tr><td>Person (3+ references)</td><td>40-80</td></tr><tr><td>Place/restaurant</td><td>20-40</td></tr><tr><td>Company</td><td>25-50</td></tr><tr><td>Philosophy/pattern/relationship</td><td>40-80</td></tr><tr><td>Era</td><td>60-100</td></tr><tr><td>Decision/transition</td><td>40-70</td></tr><tr><td>Experiment/idea</td><td>25-45</td></tr><tr><td>Minimum (anything)</td><td>15</td></tr></tbody></table><hr><h2 id="command-wiki-rebuild-index" tabindex="-1">Command: <code>/wiki rebuild-index</code> <a class="header-anchor" href="#command-wiki-rebuild-index" aria-label="Permalink to &quot;Command: \`/wiki rebuild-index\`&quot;">​</a></h2><p>Rebuild <code>_index.md</code> and <code>_backlinks.json</code> from current wiki state. Each index entry needs an <code>also:</code> field with aliases for matching entry text to articles.</p><h2 id="command-wiki-reorganize" tabindex="-1">Command: <code>/wiki reorganize</code> <a class="header-anchor" href="#command-wiki-reorganize" aria-label="Permalink to &quot;Command: \`/wiki reorganize\`&quot;">​</a></h2><p>Step back and rethink wiki structure. Read the index, sample articles, ask: merge? split? new categories? orphan articles? missing patterns? Execute changes, then rebuild index.</p><h2 id="command-wiki-status" tabindex="-1">Command: <code>/wiki status</code> <a class="header-anchor" href="#command-wiki-status" aria-label="Permalink to &quot;Command: \`/wiki status\`&quot;">​</a></h2><p>Show stats: entries absorbed, articles by category, most-connected articles, orphans, pending entries.</p><hr><h2 id="principles" tabindex="-1">Principles <a class="header-anchor" href="#principles" aria-label="Permalink to &quot;Principles&quot;">​</a></h2><ol><li><strong>You are a writer.</strong> Read entries, understand what they mean, write articles that capture that understanding.</li><li><strong>Every entry ends up somewhere.</strong> Woven into the fabric of understanding, not mechanically filed.</li><li><strong>Articles are knowledge, not diary entries.</strong> Synthesize, don&#39;t summarize.</li><li><strong>Concept articles are essential.</strong> Patterns, themes, arcs. These are where the wiki becomes a map of a mind.</li><li><strong>Revise your work.</strong> Re-read articles. Rewrite the ones that read like event logs.</li><li><strong>Breadth and depth.</strong> Create pages aggressively, but every page must gain real substance. 40 stubs is as bad as 5 bloated articles.</li><li><strong>The structure is alive.</strong> Merge, split, rename, restructure freely.</li><li><strong>View photos.</strong> Understand what they show and integrate them into the narrative.</li><li><strong>Connect, don&#39;t just record.</strong> Find the web of meaning between entities.</li><li><strong>Cite sources.</strong> Every claim traces back to a raw entry ID.</li></ol><hr><h2 id="concurrency-rules" tabindex="-1">Concurrency Rules <a class="header-anchor" href="#concurrency-rules" aria-label="Permalink to &quot;Concurrency Rules&quot;">​</a></h2><ul><li>Never delete or overwrite a file without reading it first.</li><li>Re-read any article immediately before editing it.</li><li>Never modify <code>_absorb_log.json</code>.</li><li>Rebuild <code>_index.md</code> and <code>_backlinks.json</code> only at the very end of a command.</li></ul>`,152)])])}const g=t(n,[["render",o]]);export{u as __pageData,g as default};
